(async () => {
  var options = {
    filename: './ownerTest/demoTest/read/issue_1277.xlsx',
    useStyles: true,
    useSharedStrings: true
  }
  var wb = new Excel.stream.xlsx.WorkbookWriter(options);
  var ws = wb.addWorksheet('bort');
  var rows = [
    [5,'Bob',new Date()],
    [6,'Bo2b',new Date()]
  ];
  rows.forEach((row) => {
    ws.addRow(row)
  })
  wb.commit();
})()
